    "line_076": "<option>Kinderzimmer</option>",
    "line_077": "<div class=\"lb-preview-help-text\"><strong>Nur Core-Klassen:</strong> <span class=\"lb-preview-code\">lb-table-frame</span> für Rahmen/Rundung, <span class=\"lb-preview-code\">lb-table-dropdowns-visible</span> für sichtbaren Overflow, <span class=\"lb-preview-code\">lb-dropdown-layer</span> für Multiselect und <span class=\"lb-preview-code\">lb-select-layer</span> für Select.</div>",
